#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int A[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        long long cost = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (A[i][j] < A[j][i]) {
                    cost += A[j][i] - A[i][j];
                    A[i][j] = A[j][i];
                }
            }
        }
        printf("%lld\n", cost);
    }
    return 0;
}

